{
  "domain_analysis": {
    "business_context": "A global logistics platform needs to display real-time earnings breakdowns to drivers across three jurisdictions with fundamentally different labor classifications and regulatory regimes. The feature must reconcile a single product spec ('show base pay, per-delivery bonus, tips, and deductions') with employee-status drivers (California), works-council-governed drivers (Germany), and independent contractors (Indonesia).",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed component of driver compensation for a delivery or time period, calculated differently depending on employment classification (hourly wage for employees, per-task rate for contractors)." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation awarded for each completed delivery, potentially subject to different tax treatment by jurisdiction." },
      { "term": "Tips", "definition": "Gratuities from customers passed through to the driver. In employee jurisdictions, tips must be shown separately from wages and cannot offset base pay." },
      { "term": "Deductions", "definition": "Amounts subtracted from gross earnings. For employees: taxes, benefits, garnishments. For contractors: platform fees, equipment charges. The composition varies drastically by classification." },
      { "term": "Earnings Breakdown", "definition": "The itemized display of all compensation components and deductions for a given period, serving both transparency and legal compliance purposes." },
      { "term": "Driver Classification", "definition": "The legal employment status of a driver in their jurisdiction — employee or independent contractor — which determines applicable labor law, tax obligations, and required disclosure." },
      { "term": "Works Council Approval Gate", "definition": "A mandatory procedural step in Germany where the Betriebsrat must formally approve changes to compensation display systems before they can be deployed to drivers." },
      { "term": "Real-Time Earnings", "definition": "Ambiguous term in the spec — could mean live-updating dashboard, post-delivery immediate update, or per-shift running total." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "The earnings breakdown must be adapted per jurisdiction based on the driver's legal classification (employee vs. independent contractor), not presented as a single uniform format.",
      "invariant": true,
      "invariant_justification": "Showing employee-specific fields (tax withholding, benefits deductions) to contractors, or omitting legally required fields from employees, creates legal liability. The data model is structurally different per classification.",
      "testable_assertion": "Given a driver in jurisdiction X, the earnings breakdown must display exactly the set of line items required by that jurisdiction's labor law and classification."
    },
    {
      "id": "BR-2",
      "rule": "In California, the earnings breakdown must comply with Labor Code §226 pay stub requirements: gross wages earned, total hours worked, all deductions itemized, net wages earned, pay period dates, and employer identification.",
      "invariant": true,
      "invariant_justification": "California Labor Code §226 violations carry statutory penalties of $50-$100 per pay period per employee. This is a hard legal constraint that cannot be waived.",
      "testable_assertion": "A California driver's earnings breakdown includes all §226-mandated fields: gross wages, hours worked, itemized deductions, net wages, pay period, and employer ID."
    },
    {
      "id": "BR-3",
      "rule": "Tips must never be counted toward or offset base pay for employee-classified drivers.",
      "invariant": true,
      "invariant_justification": "Under California law (and most employee-protection regimes), tips belong to the employee and cannot be credited against minimum wage or base pay obligations. Conflating them corrupts the compensation model.",
      "testable_assertion": "In the earnings breakdown for employee-classified drivers, base pay is calculated and displayed independently of tip amounts."
    },
    {
      "id": "BR-4",
      "rule": "The feature must not be deployed to German drivers until the works council (Betriebsrat) has formally approved the compensation display system.",
      "invariant": true,
      "invariant_justification": "Under the German Works Constitution Act (BetrVG §87), deploying changes to compensation display without works council consent is illegal and can be enjoined by labor courts. This is not optional.",
      "testable_assertion": "The system enforces a deployment gate for Germany: the feature flag for German drivers cannot be enabled without a recorded works council approval event."
    },
    {
      "id": "BR-5",
      "rule": "For Indonesian independent contractors, 'deductions' must reflect platform fees and service charges, not employment-style tax withholdings or benefits deductions.",
      "invariant": false,
      "invariant_justification": "This is a business policy reflecting current contractor classification. If Indonesian law changes or the platform reclassifies drivers, the deduction categories would change.",
      "testable_assertion": "An Indonesian driver's earnings breakdown shows platform fees as deductions and does not display tax withholding or benefits-related line items."
    },
    {
      "id": "BR-6",
      "rule": "Earnings data must be available to the driver no later than delivery completion for each individual delivery.",
      "invariant": false,
      "invariant_justification": "The spec says 'real time' but the exact latency SLA is a business decision, not a physical or legal constraint. A policy update could relax this to end-of-shift.",
      "testable_assertion": "Within 60 seconds of a delivery being marked complete, the driver's earnings breakdown reflects the compensation for that delivery."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver classified as an employee in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay (with hours worked), per-delivery bonus, tips (displayed separately from base pay), itemized deductions (taxes, benefits), net earnings, and pay period dates — all compliant with CA Labor Code §226"
    },
    {
      "id": "AC-2",
      "given": "A driver in Germany where works council approval has NOT been recorded",
      "when": "The platform attempts to enable the earnings transparency feature for German drivers",
      "then": "The system blocks activation and returns an error indicating works council approval is required"
    },
    {
      "id": "AC-3",
      "given": "A driver in Germany where works council approval HAS been recorded",
      "when": "They view their earnings breakdown",
      "then": "They see a breakdown adapted to German labor law requirements including gross pay, social contribution deductions, and net pay"
    },
    {
      "id": "AC-4",
      "given": "An independent contractor driver in Indonesia completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base task rate, per-delivery bonus, tips, and platform fee deductions — with no employment-style tax withholdings shown"
    },
    {
      "id": "AC-5",
      "given": "A driver completes a delivery in any jurisdiction",
      "when": "They check their earnings breakdown",
      "then": "The completed delivery's earnings appear within the agreed latency threshold (no stale data from before the delivery)"
    },
    {
      "id": "AC-6",
      "given": "A driver in any jurisdiction views their earnings breakdown",
      "when": "The breakdown is rendered",
      "then": "Tips are shown as a separate line item and are never aggregated into or offset against base pay"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver relocates from Indonesia (contractor) to California (employee) mid-pay-period",
      "expected_behavior": "Historical earnings remain displayed under the original classification. New earnings after reclassification use the employee format. The transition point must be clearly demarcated to avoid legal exposure in either jurisdiction."
    },
    {
      "scenario": "A delivery crosses jurisdiction boundaries (e.g., pickup in one region, dropoff in another)",
      "expected_behavior": "Compensation classification follows the driver's home jurisdiction classification, not the delivery geography. The earnings breakdown format remains consistent with the driver's employment status."
    },
    {
      "scenario": "German works council approval is revoked after feature deployment",
      "expected_behavior": "The system must support disabling the feature for German drivers without data loss. Previously displayed earnings data must remain accessible through alternative channels (e.g., payroll office)."
    },
    {
      "scenario": "A California driver receives zero tips on a delivery",
      "expected_behavior": "The tips line item still appears with a $0.00 value. Omitting the line item could be interpreted as the platform withholding tip information, violating transparency requirements."
    },
    {
      "scenario": "Deductions exceed gross earnings for a period (e.g., equipment charge-back for a contractor)",
      "expected_behavior": "The breakdown shows a negative net amount. The system must not silently clamp to zero — the driver must see the true balance. For employees, negative net pay may be illegal and must trigger an alert."
    },
    {
      "scenario": "Real-time display during an active delivery before completion",
      "expected_behavior": "The spec is ambiguous here. If shown, projected/estimated earnings must be clearly labeled as estimates to avoid being construed as wage commitments (especially for California employees)."
    }
  ],

  "business_impact": {
    "financial": "Non-compliance with CA Labor Code §226 exposes the platform to $50-$100 per violation per pay period per driver — at scale this is existential. Correct implementation builds driver trust and reduces churn, lowering recruitment costs. Works council violations in Germany can result in injunctions halting operations entirely.",
    "operational": "Requires per-jurisdiction configuration of earnings line items, a works council approval workflow for Germany, and a feature-flag system that gates rollout by region. Adds ongoing maintenance burden as labor laws evolve. The 'real-time' requirement demands event-driven architecture for earnings calculation.",
    "user": "Drivers gain visibility into how they are compensated, increasing trust and satisfaction. However, exposing deduction details (especially for contractors seeing platform fees) may trigger disputes or negative sentiment if not accompanied by clear explanations.",
    "risk": "HIGH legal risk if the feature ships without jurisdiction-specific adaptation. Treating all drivers identically across employee/contractor classifications is the single most dangerous failure mode. Moderate risk of works council conflict delaying Germany launch indefinitely.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Gain legally mandated wage transparency; incorrect implementation directly harms them and exposes platform to class-action liability" },
      { "group": "Drivers (Germany)", "impact": "Cannot receive feature until works council approves; delayed access relative to other regions" },
      { "group": "Drivers (Indonesia)", "impact": "Receive optional transparency benefit; risk seeing platform fees explicitly for the first time, potentially causing friction" },
      { "group": "Legal/Compliance Team", "impact": "Must validate per-jurisdiction requirements before each regional launch; ongoing obligation to monitor regulatory changes" },
      { "group": "German Works Council (Betriebsrat)", "impact": "Must be formally engaged and given approval authority; failure to involve them is a legal violation independent of the feature's content" },
      { "group": "Product/Engineering", "impact": "Must build a jurisdiction-aware earnings model rather than a single global template; significantly increases complexity" },
      { "group": "Finance/Payroll", "impact": "Earnings breakdown must reconcile exactly with payroll records; any discrepancy creates audit and trust issues" }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The feature spec provides a single uniform description ('base pay, per-delivery bonus, tips, and deductions') but the three jurisdictions require fundamentally different interpretations of each term — particularly 'deductions' and 'base pay.' The spec does not acknowledge these differences, creating ambiguity about whether jurisdiction-specific adaptation is intended or whether the team expects a single global format. Additionally, 'real time' is undefined, and the specific line items required under each jurisdiction's law need legal review to finalize.",
    "high_confidence_areas": [
      "Tips must be separate from base pay for employee-classified drivers",
      "Works council approval is a hard gate for Germany — non-negotiable",
      "Employee vs. contractor classification fundamentally changes what 'deductions' means",
      "California has specific statutory requirements for pay stub content under §226"
    ],
    "low_confidence_areas": [
      "Exact German labor law requirements for earnings display format after works council approval",
      "Whether Indonesian regulations impose any contractor payment disclosure requirements we are unaware of",
      "How the platform currently handles driver classification transitions between jurisdictions"
    ],
    "assumptions": [
      "The platform has an authoritative source for each driver's jurisdiction and classification",
      "The works council approval process is a one-time gate per feature, not per-driver",
      "California AB5 classification applies to all drivers on the platform in California",
      "The platform already calculates these earnings components server-side and this feature is about display, not computation"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec describes a single earnings breakdown format ('base pay, per-delivery bonus, tips, and deductions') but the three target jurisdictions have fundamentally incompatible requirements for what these terms mean and what must be displayed. It is ambiguous whether the product team intends a single global template or jurisdiction-specific adaptations.",
      "affected_stakeholders": ["Product/Engineering", "Legal/Compliance Team", "Drivers (all regions)"],
      "options": [
        "A: Build a single global template with the union of all fields, hiding irrelevant ones per jurisdiction",
        "B: Build jurisdiction-specific earnings breakdown templates, each tailored to local law and classification",
        "C: Build a core template with jurisdiction-specific extension points"
      ],
      "recommendation": "Option B — jurisdiction-specific templates. The legal requirements are different enough that a single template risks either showing legally incorrect information or omitting legally required information. Option C is acceptable if the team wants shared UI infrastructure."
    },
    {
      "type": "ambiguity",
      "description": "'Real time' is undefined. For California employees, this distinction matters legally: showing projected earnings during an active delivery could be construed as a wage commitment, while delayed display after shift-end may not satisfy the transparency intent. The spec needs to define the latency and trigger (per-delivery, per-shift, or live-updating).",
      "affected_stakeholders": ["Product/Engineering", "Drivers (all regions)", "Legal/Compliance Team"],
      "options": [
        "A: Real-time means a live-updating dashboard refreshed continuously",
        "B: Real-time means earnings appear immediately after each delivery completes",
        "C: Real-time means a running total updated at the end of each shift"
      ],
      "recommendation": "Option B — per-delivery completion update. It satisfies the transparency intent without the legal risk of showing projections (Option A) or the staleness of shift-end batching (Option C)."
    },
    {
      "type": "ambiguity",
      "description": "'Deductions' has completely different compositions for employees vs. contractors. For California employees: taxes, Social Security, Medicare, benefits premiums, garnishments. For Indonesian contractors: platform commission, service fees, insurance opt-ins. The spec uses one word for two fundamentally different domain concepts.",
      "affected_stakeholders": ["Drivers (all regions)", "Finance/Payroll", "Legal/Compliance Team"],
      "options": [
        "A: Use 'Deductions' as a generic label with jurisdiction-specific sub-items",
        "B: Use different terminology per classification: 'Withholdings & Deductions' for employees, 'Platform Fees' for contractors",
        "C: Require product to define the exact line items per jurisdiction before implementation begins"
      ],
      "recommendation": "Option C first (define the items), then Option B for display. Using the same label for structurally different concepts violates domain clarity and could confuse drivers or create legal ambiguity."
    }
  ],

  "rejection_reasons": []
}

